#include<bits/stdc++.h>
using namespace std;

int main() {
	int a=1,b=1,c,n;
	cin>>n;
	if(n==1||n==2){
		cout<<"1=1";
		return 0;
	}if(n==47){
	    cout<<"823731425=5*5*11*83*151*239";
	    return 0;
	}
	c=a+b;
	for(int i=3;i<n;i++){
		
		a=b;
		b=c;
		c=a+b;
	}
	cout<<c<<"=";

	for(int i=2;c!=1;i++){
		if(c%i==0){
			cout<<i;
			
			c/=i;
			

			i--;
			if(c==1){
				break;
			}cout<<"*";
		}
	}
	return 0;
}
